doc = Rhino.RhinoDoc.ActiveDoc
breps = []
picked_ids = []
for obj in doc.Objects.GetSelectedObjects(False, False):
    if isinstance(obj.Geometry, Rhino.Geometry.Brep):
        breps.append(obj.Geometry)
        picked_ids.append(obj.Id)
if len(breps) < 2:
    return {"ok": False, "error": "need at least 2 selected breps; got %d" % len(breps)}
tol = doc.ModelAbsoluteTolerance
result = Rhino.Geometry.Brep.CreateBooleanUnion(breps, tol)
if result is None or len(result) == 0:
    return {"ok": False, "error": "boolean union returned no breps"}
for obj_id in picked_ids:
    doc.Objects.Delete(obj_id, True)
new_ids = []
for brep in result:
    new_ids.append(str(doc.Objects.AddBrep(brep)))
doc.Views.Redraw()
return {"ok": True, "inputs": len(picked_ids), "outputs": len(new_ids), "ids": new_ids}
